diff --git a/src/cli.ts b/src/cli.ts
new file mode 100644
--- /dev/null
+++ b/src/cli.ts
@@ -0,0 +1,7 @@
+import { add, subtract, multiply, divide } from './calc.ts';
+const [op, a, b] = process.argv.slice(2);
+const x = Number(a), y = Number(b);
+const ops: Record<string, (a: number, b: number) => number> = { add, subtract, multiply, divide };
+const fn = ops[op];
+if (!fn) { console.error('unknown op:', op); process.exit(1); }
+console.log(fn(x, y));
